# Route Organization and Handlers

## Basic Route Definition

Define routes with the shorthand methods or the full route method:

```typescript
import Fastify from 'fastify';

const app = Fastify();

// Shorthand methods
app.get('/users', async (request, reply) => {
  return { users: [] };
});

app.post('/users', async (request, reply) => {
  return { created: true };
});

// Full route method with all options
app.route({
  method: 'GET',
  url: '/users/:id',
  schema: {
    params: {
      type: 'object',
      properties: {
        id: { type: 'string' },
      },
      required: ['id'],
    },
  },
  handler: async (request, reply) => {
    return { id: request.params.id };
  },
});
```

## Route Parameters

Access URL parameters through `request.params`:

```typescript
// Single parameter
app.get('/users/:id', async (request) => {
  const { id } = request.params as { id: string };
  return { userId: id };
});

// Multiple parameters
app.get('/users/:userId/posts/:postId', async (request) => {
  const { userId, postId } = request.params as { userId: string; postId: string };
  return { userId, postId };
});

// Wildcard parameter (captures everything after)
app.get('/files/*', async (request) => {
  const path = (request.params as { '*': string })['*'];
  return { filePath: path };
});

// Regex parameters (Fastify uses find-my-way)
app.get('/orders/:id(\\d+)', async (request) => {
  // Only matches numeric IDs
  const { id } = request.params as { id: string };
  return { orderId: parseInt(id, 10) };
});
```

## Query String Parameters

Access query parameters through `request.query`:

```typescript
app.get('/search', {
  schema: {
    querystring: {
      type: 'object',
      properties: {
        q: { type: 'string' },
        page: { type: 'integer', default: 1 },
        limit: { type: 'integer', default: 10, maximum: 100 },
      },
      required: ['q'],
    },
  },
  handler: async (request) => {
    const { q, page, limit } = request.query as {
      q: string;
      page: number;
      limit: number;
    };
    return { query: q, page, limit };
  },
});
```

## Request Body

Access the request body through `request.body`:

```typescript
app.post('/users', {
  schema: {
    body: {
      type: 'object',
      properties: {
        name: { type: 'string', minLength: 1 },
        email: { type: 'string', format: 'email' },
        age: { type: 'integer', minimum: 0 },
      },
      required: ['name', 'email'],
    },
  },
  handler: async (request, reply) => {
    const user = request.body as { name: string; email: string; age?: number };
    // Create user...
    reply.code(201);
    return { user };
  },
});
```

## Headers

Access request headers through `request.headers`:

```typescript
app.get('/protected', {
  schema: {
    headers: {
      type: 'object',
      properties: {
        authorization: { type: 'string' },
      },
      required: ['authorization'],
    },
  },
  handler: async (request) => {
    const token = request.headers.authorization;
    return { authenticated: true };
  },
});
```

## Reply Methods

Use reply methods to control the response:

```typescript
app.get('/examples', async (request, reply) => {
  // Set status code
  reply.code(201);

  // Set headers
  reply.header('X-Custom-Header', 'value');
  reply.headers({ 'X-Another': 'value', 'X-Third': 'value' });

  // Set content type
  reply.type('application/json');

  // Redirect
  // reply.redirect('/other-url');
  // reply.redirect(301, '/permanent-redirect');

  // Return response (automatic serialization)
  return { status: 'ok' };
});

// Explicit send (useful in non-async handlers)
app.get('/explicit', (request, reply) => {
  reply.send({ status: 'ok' });
});

// Stream response
app.get('/stream', async (request, reply) => {
  const stream = fs.createReadStream('./large-file.txt');
  reply.type('text/plain');
  return reply.send(stream);
});
```

## Route Organization by Feature

Organize routes by feature/domain in separate files:

```
src/
  routes/
    users/
      index.ts       # Route definitions
      handlers.ts    # Handler functions
      schemas.ts     # JSON schemas
    posts/
      index.ts
      handlers.ts
      schemas.ts
```

```typescript
// routes/users/schemas.ts
export const userSchema = {
  type: 'object',
  properties: {
    id: { type: 'string', format: 'uuid' },
    name: { type: 'string' },
    email: { type: 'string', format: 'email' },
  },
};

export const createUserSchema = {
  body: {

import type {
  AutomatonRecord,
  MonologueEntry
} from "./automaton.js";
import type {
  SessionAuditEntry,
  SpawnSession
} from "./spawn.js";

export const AUTOMATON_EVENT_TYPES = [
  "spawn",
  "update",
  "action",
  "message",
  "monologue",
  "offline"
] as const;

export const SPAWN_EVENT_TYPES = [
  "spawn.session.updated",
  "spawn.session.completed",
  "spawn.session.failed",
  "spawn.session.expired"
] as const;

export type AutomatonEventType = (typeof AUTOMATON_EVENT_TYPES)[number];
export type SpawnEventType = (typeof SPAWN_EVENT_TYPES)[number];

export interface AutomatonSpawnEvent {
  type: "spawn";
  automaton: AutomatonRecord;
}

export interface AutomatonUpdateEvent {
  type: "update";
  canisterId: string;
  changes: Partial<AutomatonRecord>;
  timestamp: number;
}

export interface AutomatonActionEvent {
  type: "action";
  canisterId: string;
  action: string;
  turnId: string | null;
  timestamp: number;
}

export interface AutomatonMessageEvent {
  type: "message";
  fromCanisterId: string;
  toCanisterId: string;
  timestamp: number;
}

export interface AutomatonMonologueEvent {
  type: "monologue";
  canisterId: string;
  entry: MonologueEntry;
}

export interface AutomatonOfflineEvent {
  type: "offline";
  canisterId: string;
  timestamp: number;
}

export interface SpawnSessionUpdatedEvent {
  type: "spawn.session.updated";
  session: SpawnSession;
  audit: SessionAuditEntry[];
}

export interface SpawnSessionCompletedEvent {
  type: "spawn.session.completed";
  session: SpawnSession;
  audit: SessionAuditEntry[];
}

export interface SpawnSessionFailedEvent {
  type: "spawn.session.failed";
  session: SpawnSession;
  audit: SessionAuditEntry[];
}

export interface SpawnSessionExpiredEvent {
  type: "spawn.session.expired";
  session: SpawnSession;
  audit: SessionAuditEntry[];
}

export type RealtimeEvent =
  | AutomatonSpawnEvent
  | AutomatonUpdateEvent
  | AutomatonActionEvent
  | AutomatonMessageEvent
  | AutomatonMonologueEvent
  | AutomatonOfflineEvent
  | SpawnSessionUpdatedEvent
  | SpawnSessionCompletedEvent
  | SpawnSessionFailedEvent
  | SpawnSessionExpiredEvent;

export const SUPPORTED_SPAWN_CHAINS = ["base"] as const;
export const SUPPORTED_SPAWN_ASSETS = ["eth", "usdc"] as const;

export const SPAWN_SESSION_STATES = [
  "awaiting_payment",
  "payment_detected",
  "spawning",
  "funding_automaton",
  "complete",
  "failed",
  "expired"
] as const;

export const PAYMENT_STATUSES = [
  "unpaid",
  "partial",
  "paid",
  "refunded"
] as const;

export const SESSION_AUDIT_ACTORS = [
  "system",
  "user",
  "admin",
  "escrow"
] as const;

export const MINIMUM_GROSS_PAYMENT_USD = 50;

export type SpawnChain = (typeof SUPPORTED_SPAWN_CHAINS)[number];
export type SpawnAsset = (typeof SUPPORTED_SPAWN_ASSETS)[number];
export type SpawnSessionState = (typeof SPAWN_SESSION_STATES)[number];
export type PaymentStatus = (typeof PAYMENT_STATUSES)[number];
export type SessionAuditActor = (typeof SESSION_AUDIT_ACTORS)[number];

export interface ProviderConfig {
  openRouterApiKey: string | null;
  model: string | null;
  braveSearchApiKey: string | null;
}

export interface SpawnConfig extends ProviderConfig {
  chain: SpawnChain;
  risk: number;
  strategies: string[];
  skills: string[];
}

export interface SpawnPaymentInstructions {
  sessionId: string;
  chain: SpawnChain;
  asset: SpawnAsset;
  paymentAddress: string;
  grossAmount: string;
  quoteTermsHash: string;
  expiresAt: number;
}

export interface SpawnQuote {
  sessionId: string;
  chain: SpawnChain;
  asset: SpawnAsset;
  grossAmount: string;
  platformFee: string;
  creationCost: string;
  netForwardAmount: string;
  quoteTermsHash: string;
  expiresAt: number;
  payment: SpawnPaymentInstructions;
}

export interface SpawnSession {
  sessionId: string;
  stewardAddress: string;
  chain: SpawnChain;
  asset: SpawnAsset;
  grossAmount: string;
  platformFee: string;
  creationCost: string;
  netForwardAmount: string;
  quoteTermsHash: string;
  expiresAt: number;
  state: SpawnSessionState;
  retryable: boolean;
  refundable: boolean;
  paymentStatus: PaymentStatus;
  automatonCanisterId: string | null;
  automatonEvmAddress: string | null;
  parentId: string | null;
  childIds: string[];
  config: SpawnConfig;
  createdAt: number;
  updatedAt: number;
}

